import json
d=json.load(open('.leandag/dag.json'))
nodes=d['nodes'] if 'nodes' in d else d
byid={n['id']:n for n in nodes}
adj={n['id']:set() for n in nodes}
for n in nodes:
    for u in (n.get('uses') or []):
        if u in adj: adj[n['id']].add(u); adj[u].add(n['id'])
seen=set(); comps=[]
for s in adj:
    if s in seen: continue
    stack=[s]; comp=[]
    while stack:
        x=stack.pop()
        if x in seen: continue
        seen.add(x); comp.append(x); stack.extend(adj[x]-seen)
    comps.append(comp)
comps.sort(key=len,reverse=True)
# the giant is comps[0]; print the rest with chapters
for c in comps[1:]:
    chs=set(byid[i].get('chapter','?') for i in c)
    print(f'--- size {len(c)}  chapters={sorted(chs)}')
    for i in sorted(c)[:30]:
        print('    ', i)
" 2>/dev/null | head -120

